mapper.select:
SELECT s.solution_id, s.algorithm, s.`type`, s.language, s.code, s.user_problem_id, s.created_at
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.solution_id = #{solutionId}

SELECT COUNT(*)
FROM user_problems
WHERE user_id = #{userId}
  AND user_problem_id = #{userProblemId}

SELECT COUNT(*)
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.user_problem_id = #{userProblemId}

mapper.update:
UPDATE user_problems
SET last_solved_date = #{lastSolvedDate},
	solve_count = COALESCE(solve_count, 0) + 1
WHERE user_id = #{userId}
  AND user_problem_id = #{userProblemId}

mapper.delete:
DELETE s
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.solution_id = #{solutionId}
